            $code = $this->safe_currency_code($currencyId);
            $name = $this->safe_string($currency, 'name');
            $networks = array();
            $chains = $this->safe_list($currency, 'networkList', array());
            for ($j = 0; $j < count($chains); $j++) {
                $chain = $this->safe_dict($chains, $j);
                $networkId = $this->safe_string($chain, 'network');
                $networkCode = $this->network_id_to_code($networkId);
                $networks[$networkCode] = array(
                    'info' => $chain,
                    'id' => $networkId,
                    'network' => $networkCode,
                    'active' => null,
                    'deposit' => $this->safe_bool($chain, 'depositEnable'),
                    'withdraw' => $this->safe_bool($chain, 'withdrawEnable'),
                    'fee' => $this->safe_number($chain, 'withdrawFee'),
                    'precision' => $this->safe_number($chain, 'withdrawIntegerMultiple'),
                    'isDefault' => $this->safe_bool($chain, 'isDefault', false),
                    'limits' => array(
                        'withdraw' => array(
                            'min' => $this->safe_number($chain, 'withdrawMin'),
                            'max' => null,
                        ),
                        'deposit' => array(
                            'min' => $this->safe_number($chain, 'depositDust'),
                            'max' => null,
                        ),
                    ),
                );
            }
            $networkKeys = is_array($networks) ? array_keys($networks) : array();
            $networksLength = count($networkKeys);
            $emptyChains = $networksLength === 0; // non-functional coins
            $valueForEmpty = $emptyChains ? false : null;
            $result[$code] = $this->safe_currency_structure(array(
                'info' => $currency,
                'code' => $code,
                'id' => $currencyId,
                'type' => 'crypto',
                'name' => $name,
                'active' => null,
                'deposit' => $valueForEmpty,
                'withdraw' => $valueForEmpty,
                'fee' => null,
                'precision' => null,
                'limits' => array(
                    'amount' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'withdraw' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'deposit' => array(
                        'min' => null,
                        'max' => null,
                    ),
                ),
                'networks' => $networks,
            ));
        }
        return $result;
    }

    public function fetch_markets($params = array ()): array {
        /**
         * retrieves data on all markets for exchagne
         *
         * @see https://www.weex.com/api-doc/spot/ConfigAPI/GetProductInfo // spot
         * @see https://www.weex.com/api-doc/contract/Market_API/GetContractInfo // contract
         *
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array[]} an array of objects representing market data
         */
        if ($this->options['adjustForTimeDifference']) {
            $this->load_time_difference();
        }
        $promises = array(
            $this->publicGetApiV3ExchangeInfo ($params),
            $this->contractGetCapiV3MarketExchangeInfo ($params),
        );
        list($spotResponse, $contractResponse) = $promises;
        $spotArray = $this->safe_list($spotResponse, 'symbols', array());
        $contractArray = $this->safe_list($contractResponse, 'symbols', array());
        $result = $this->array_concat($spotArray, $contractArray);
        return $this->parse_markets($result);
    }

    public function parse_market(array $market): array {
        //
        // spot
        //     {
        //         "symbol" => "ETHUSDT",
        //         "status" => "TRADING",
        //         "baseAsset" => "ETH",
        //         "baseAssetPrecision" => "8",
        //         "quoteAsset" => "USDT",
        //         "quoteAssetPrecision" => "8",
        //         "tickSize" => "0.01",
        //         "stepSize" => "0.00001",
        //         "minTradeAmount" => "0.0001",
        //         "maxTradeAmount" => "99999",
        //         "takerFeeRate" => "0.001",
        //         "makerFeeRate" => "0.001",
        //         "buyLimitPriceRatio" => "0.1",
        //         "sellLimitPriceRatio" => "0.1",
        //         "marketBuyLimitSize" => "99999",
        //         "marketSellLimitSize" => "99999",
        //         "marketFallbackPriceRatio" => "0",
        //         "enableTrade" => true,
        //         "enableDisplay" => true,
        //         "displayDigitMerge" => "0.01,0.1,0.5,1,5",
        //         "displayNew" => false,
        //         "displayHot" => false
        //     }
        //
        // contract
        //     {
        //         "symbol" => "ETHUSDT",
        //         "baseAsset" => "ETH",
        //         "quoteAsset" => "USDT",
        //         "marginAsset" => "USDT",
        //         "pricePrecision" => "2",
        //         "quantityPrecision" => "3",
        //         "baseAssetPrecision" => "2",
        //         "quotePrecision" => "8",
        //         "contractVal" => "0.001",
        //         "delivery" => array(
        //             "00:00:00",
        //             "08:00:00",
        //             "16:00:00"
        //         ),
        //         "forwardContractFlag" => true,
        //         "minLeverage" => "1",
        //         "maxLeverage" => "400",
        //         "buyLimitPriceRatio" => "0.01",
        //         "sellLimitPriceRatio" => "0.01",
        //         "makerFeeRate" => "0.0002",
        //         "takerFeeRate" => "0.0008",
        //         "minOrderSize" => "0.001",
        //         "maxOrderSize" => "1000000",
        //         "maxPositionSize" => "5000000",
        //         "marketOpenLimitSize" => "2300"
        //     }
        //
        $id = $this->safe_string($market, 'symbol');
        $baseId = $this->safe_string($market, 'baseAsset');
        $quoteId = $this->safe_string($market, 'quoteAsset');
        $settleId = $this->safe_string($market, 'marginAsset');
        $base = $this->safe_currency_code($baseId);
        $quote = $this->safe_currency_code($quoteId);
        $settle = $this->safe_currency_code($settleId);
        $active = true;
        $symbol = $base . '/' . $quote;
        $isSpot = true;
        $isLinear = null;
        $isInverse = null;
        if ($settle !== null) {
            $symbol .= ':' . $settle;
            $isSpot = false;
            if ($settle === $quote) {
                $isLinear = true;
                $isInverse = false;
            } elseif ($settle === $base) {
                $isLinear = false;
                $isInverse = true;
            }
        } else {
            $active = $this->safe_bool($market, 'enableTrade');
        }
        $amountPrecision = $this->safe_number($market, 'stepSize');
        $pricePrecision = $this->safe_number($market, 'tickSize');
        if ($amountPrecision === null) {
            $amountPrecisionString = $this->parse_precision($this->safe_string($market, 'quantityPrecision'));
            $pricePrecisionString = $this->parse_precision($this->safe_string($market, 'pricePrecision'));
            $amountPrecision = $this->parse_number($amountPrecisionString);
            $pricePrecision = $this->parse_number($pricePrecisionString);
        }
        $fees = $this->safe_dict($this->fees, $isSpot ? 'spot' : 'contract', array());
        return $this->safe_market_structure(array(
            'id' => $id,
            'lowercaseId' => strtolower($id),
            'numericId' => $this->safe_integer($market, 'contractId'),
            'symbol' => $symbol,
            'base' => $base,
            'quote' => $quote,
            'settle' => $settle,
            'baseId' => $baseId,
            'quoteId' => $quoteId,
            'settleId' => $settleId,
            'type' => $isSpot ? 'spot' : 'swap',
            'spot' => $isSpot,
            'margin' => false,
            'swap' => !$isSpot,
            'future' => false,
            'option' => false,
            'active' => $active,
            'contract' => !$isSpot,
            'linear' => $isLinear,
            'inverse' => $isInverse,
            'taker' => $this->safe_number($market, 'takerFeeRate'),
            'maker' => $this->safe_number($market, 'makerFeeRate'),
            'feeSide' => $fees['feeSide'],
            'contractSize' => $this->safe_number($market, 'contractVal'),
            'expiry' => null,
            'expiryDatetime' => null,
            'strike' => null,
            'optionType' => null,
            'precision' => array(
                'amount' => $amountPrecision,
                'price' => $pricePrecision,
            ),
            'limits' => array(
                'leverage' => array(
                    'min' => $this->safe_number($market, 'minLeverage'),
                    'max' => $this->safe_number($market, 'maxLeverage'),
                ),
                'amount' => array(
                    'min' => $this->safe_number_2($market, 'minTradeAmount', 'minOrderSize'),
                    'max' => $this->safe_number_2($market, 'maxTradeAmount', 'maxOrderSize'),
                ),
                'price' => array(
                    'min' => null,
                    'max' => null,
                ),
                'cost' => array(
                    'min' => null,
                    'max' => null,
                ),
            ),
            'created' => null,
            'percentage' => $fees['percentage'],
            'tierBased' => $fees['tierBased'],
            'tiers' => $fees['tiers'],
            'info' => $market,
        ));
    }

    public function fetch_tickers(?array $symbols = null, $params = array ()): array {
        /**
         * fetches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific $market
         *
         * @see https://www.weex.com/api-doc/spot/MarketDataAPI/GetAllTickerInfo // spot
         * @see https://www.weex.com/api-doc/contract/Market_API/GetTicker24h // contract
         *
         * @param {string} $symbols unified symbol of the $market to fetch the ticker for
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->type] 'spot' or 'swap', default is 'spot' (used if $symbols are not provided)
         * @return {array} a ~@link https://docs.ccxt.com/?id=ticker-structure ticker structure~
         */
        $this->load_markets();
        $symbols = $this->market_symbols($symbols, null, true, true);
        $market = $this->get_market_from_symbols($symbols);
        $marketType = null;
        list($marketType, $params) = $this->handle_market_type_and_params('fetchTickers', $market, $params);
        $symbolsLength = 0;
        if ($symbols !== null) {
            $symbolsLength = count($symbols);
        }
        $request = array();
        if ($symbolsLength === 1) {
            $request['symbol'] = $market['id'];
        }
        $response = null;
        if ($marketType === 'spot') {
            //
            //     array(
            //         {
            //             "symbol" => "ETHUSDT",
            //             "priceChange" => "-72.98",
            //             "priceChangePercent" => "-0.033811",
            //             "lastPrice" => "2085.46",
            //             "bidPrice" => "2085.44",
            //             "bidQty" => "1.53848",
            //             "askPrice" => "2085.47",
            //             "askQty" => "1.87504",
            //             "openPrice" => "2158.44",
            //             "highPrice" => "2168.40",
            //             "lowPrice" => "2061.12",
            //             "volume" => "157359.56105",
            //             "quoteVolume" => "331284305.7193626",
            //             "openTime" => 1775493000000,
            //             "closeTime" => 1775579400000,
            //             "count" => 59727
            //         }
            //     )
            //
            $response = $this->publicGetApiV3MarketTicker24hr ($this->extend($request, $params));
        } else {
            //
            //     array(
            //         {
            //             "symbol" => "ETHUSDT",
            //             "priceChange" => "-75.49",
            //             "priceChangePercent" => "-0.034992",
            //             "lastPrice" => "2081.80",
            //             "openPrice" => "2157.29",
            //             "highPrice" => "2167.51",
            //             "lowPrice" => "2059.17",
            //             "volume" => "623160.426",
            //             "quoteVolume" => "1310647345.19346",
            //             "openTime" => 1775493000000,
            //             "closeTime" => 1775579400000,
            //             "markPrice" => "2081.8",
            //             "indexPrice" => "2082.75"
            //         }
            //     )
            //
            $response = $this->contractGetCapiV3MarketTicker24hr ($this->extend($request, $params));
        }
        if ((gettype($response) !== 'array' || array_keys($response) !== array_keys(array_keys($response)))) {
            $response = array( $response );
        }
        return $this->parse_tickers($response, $symbols);
    }

    public function fetch_bids_asks(?array $symbols = null, $params = array ()) {
        /**
         * fetches the bid and ask price and volume for multiple markets
         *
         * @see https://www.weex.com/api-doc/spot/MarketDataAPI/GetBookTicker // spot
         * @see https://www.weex.com/api-doc/contract/Market_API/GetBookTicker // contract
         *
         * @param {string[]|null} $symbols unified $symbols of the markets to fetch the bids and asks for, all markets are returned if not assigned
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->type] 'spot' or 'swap', default is 'spot' (used if $symbols are not provided)
         * @return {array} a dictionary of ~@link https://docs.ccxt.com/?id=ticker-structure ticker structures~
         */
        $symbols = $this->market_symbols($symbols, null, true, true);
        $market = $this->get_market_from_symbols($symbols);
        $marketType = null;
        list($marketType, $params) = $this->handle_market_type_and_params('fetchTickers', $market, $params);
        $response = null;
        if ($marketType === 'spot') {
            $response = $this->publicGetApiV3MarketTickerBookTicker ($params);
        } else {
            $response = $this->contractGetCapiV3MarketTickerBookTicker ($params);
        }
        if ((gettype($response) !== 'array' || array_keys($response) !== array_keys(array_keys($response)))) {
            $response = array( $response );
        }
        return $this->parse_tickers($response, $symbols);
    }

    public function parse_ticker(array $ticker, ?array $market = null): array {
        //
        // spot
        //     {
        //         "symbol" => "ETHUSDT",
        //         "priceChange" => "-72.98",
        //         "priceChangePercent" => "-0.033811",
        //         "lastPrice" => "2085.46",
        //         "bidPrice" => "2085.44",
        //         "bidQty" => "1.53848",
        //         "askPrice" => "2085.47",
        //         "askQty" => "1.87504",
        //         "openPrice" => "2158.44",
        //         "highPrice" => "2168.40",
        //         "lowPrice" => "2061.12",
        //         "volume" => "157359.56105",
        //         "quoteVolume" => "331284305.7193626",
        //         "openTime" => 1775493000000,
        //         "closeTime" => 1775579400000,
        //         "count" => 59727
        //     }
        //
        // swap
        //     {
        //         "symbol" => "ETHUSDT",
        //         "priceChange" => "-75.49",
        //         "priceChangePercent" => "-0.034992",
        //         "lastPrice" => "2081.80",
        //         "openPrice" => "2157.29",
        //         "highPrice" => "2167.51",
        //         "lowPrice" => "2059.17",
        //         "volume" => "623160.426",
        //         "quoteVolume" => "1310647345.19346",
        //         "openTime" => 1775493000000,
        //         "closeTime" => 1775579400000,
        //         "markPrice" => "2081.8",
        //         "indexPrice" => "2082.75"
        //     }
        //
        $marketId = $this->safe_string($ticker, 'symbol');
        $markPrice = $this->safe_string($ticker, 'markPrice');
        $marketType = 'spot';
        if ($markPrice !== null) {
            $marketType = 'swap';
        }
        $market = $this->safe_market($marketId, $market, null, $marketType);
        $timestamp = $this->safe_integer_2($ticker, 'closeTime', 'time');
        return $this->safe_ticker(array(
            'symbol' => $market['symbol'],
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'high' => $this->safe_string($ticker, 'highPrice'),
            'low' => $this->safe_string($ticker, 'lowPrice'),
            'bid' => $this->safe_string($ticker, 'bidPrice'),
            'bidVolume' => $this->safe_string($ticker, 'bidQty'),
            'ask' => $this->safe_string($ticker, 'askPrice'),
            'askVolume' => $this->safe_string($ticker, 'askQty'),
            'vwap' => null,
            'open' => $this->safe_string($ticker, 'openPrice'),
            'close' => $this->safe_string($ticker, 'lastPrice'),
            'last' => $this->safe_string($ticker, 'lastPrice'),
            'previousClose' => null,
            'change' => $this->safe_string($ticker, 'priceChange'),
            'percentage' => $this->safe_string($ticker, 'priceChangePercent'),
            'average' => null,
            'baseVolume' => $this->safe_string($ticker, 'volume'),
            'quoteVolume' => $this->safe_string($ticker, 'quoteVolume'),
            'markPrice' => $markPrice,
            'indexPrice' => $this->safe_string($ticker, 'indexPrice'),
            'info' => $ticker,
        ), $market);
    }

    public function fetch_order_book(string $symbol, ?int $limit = null, $params = array ()): array {
        /**
         * fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
         *
         * @see https://www.weex.com/api-doc/spot/MarketDataAPI/GetDepthData // spot
         * @see https://www.weex.com/api-doc/contract/Market_API/GetDepthData // contract
         *
         * @param {string} $symbol unified $symbol of the $market to fetch the order book for
         * @param {int} [$limit] the maximum amount of order book entries to return (default 15, max 200)
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} A dictionary of ~@link https://docs.ccxt.com/?id=order-book-structure order book structures~ indexed by $market symbols
         */
        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'symbol' => $market['id'],
        );
        if (($limit !== null) && ($limit > 15)) {
            $request['limit'] = 200; // default is 15, max is 200
        }
        $response = null;
        if ($market['spot']) {
            $response = $this->publicGetApiV3MarketDepth ($this->extend($request, $params));
        } else {
            $response = $this->contractGetCapiV3MarketDepth ($this->extend($request, $params));
        }
        //
        //     {
        //         "asks" => array(
        //             array(
        //                 "2096.77",
        //                 "45.592"
        //             )
        //         ),
        //         "bids" => array(
        //             array(
        //                 "2096.76",
        //                 "49.162"
        //             )
        //         ),
        //         "lastUpdateId" => 14138610208
        //     }
        //
        $orderbook = $this->parse_order_book($response, $symbol);
        $orderbook['nonce'] = $this->safe_integer($response, 'lastUpdateId');
        return $orderbook;
    }

    public function fetch_ohlcv(string $symbol, string $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetches historical candlestick data containing the open, high, low, and close price, and the volume of a $market
         *
         * @see https://www.weex.com/api-doc/spot/MarketDataAPI/GetKLineData // spot
         * @see https://www.weex.com/api-doc/contract/Market_API/GetKlines // contract last price
         * @see https://www.weex.com/api-doc/contract/Market_API/GetIndexPriceKlines // contract index price
         * @see https://www.weex.com/api-doc/contract/Market_API/GetMarkPriceKlines // contract mark price
         * @see https://www.weex.com/api-doc/contract/Market_API/GetHistoryKlines // contract historical klines
         *
         * @param {string} $symbol unified $symbol of the $market to fetch OHLCV data for
         * @param {string} $timeframe the length of time each candle represents
         * @param {int} [$since] timestamp in ms of the earliest candle to fetch
         * @param {int} [$limit] the maximum amount of candles to fetch (default 100, max 300)
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * Check fetchSpotOHLCV() and fetchContractOHLCV() for more details on the extra parameters that can be used in $params
         * @return {int[][]} A list of candles ordered, open, high, low, close, volume
         */
        $this->load_markets();
        $market = $this->market($symbol);
        if ($market['spot']) {
            return $this->fetch_spot_ohlcv($symbol, $timeframe, $since, $limit, $params);
        } else {
            return $this->fetch_contract_ohlcv($symbol, $timeframe, $since, $limit, $params);
        }
    }

    public function fetch_spot_ohlcv(string $symbol, string $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * @ignore
         * helper method for fetchOHLCV
         *
         * @see https://www.weex.com/api-doc/spot/MarketDataAPI/GetKLineData
         *
         * @param {string} $symbol unified $symbol of the $market to fetch OHLCV data for
         * @param {string} $timeframe the length of time each candle represents
         * @param {int} [$since] timestamp in ms of the earliest candle to fetch
         * @param {int} [$limit] the maximum amount of candles to fetch
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {int[][]} A list of candles ordered, open, high, low, close, volume
         */
        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'symbol' => $market['id'],
            'interval' => $this->safe_string($this->timeframes, $timeframe, $timeframe),
        );
        $response = $this->publicGetApiV3MarketKlines ($this->extend($request, $params));
        return $this->parse_ohlcvs($response, $market, $timeframe, $since, $limit);
    }

    public function fetch_contract_ohlcv(string $symbol, string $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * @ignore
         * helper method for fetchOHLCV
         *
         * @see https://www.weex.com/api-doc/contract/Market_API/GetKlines // contract last price
         * @see https://www.weex.com/api-doc/contract/Market_API/GetIndexPriceKlines // contract index price
         * @see https://www.weex.com/api-doc/contract/Market_API/GetMarkPriceKlines // contract mark price
         * @see https://www.weex.com/api-doc/contract/Market_API/GetHistoryKlines // contract $historical klines
         *
         * @param {string} $symbol unified $symbol of the $market to fetch OHLCV data for
         * @param {string} $timeframe the length of time each candle represents
         * @param {int} [$since] timestamp in ms of the earliest candle to fetch
         * @param {int} [$limit] the maximum amount of candles to fetch (default 100, max 100 for $historical klines, max 1000 for other contract klines)
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {int} [$params->until] timestamp in ms of the latest candle to fetch
         * @param {boolean} [$params->paginate] whether to automatically $paginate requests $until the required number of candles is returned
         * @param {boolean} [$params->historical] whether to fetch $historical klines (default is false). If false, will fetch last price klines
         * @return {int[][]} A list of candles ordered, open, high, low, close, volume
         */
        $this->load_markets();
        $maxHistoricalLimit = 100;
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchOHLCV', 'paginate');
        if ($paginate) {
            $params = $this->extend($params, array( 'historical' => true ));
            return $this->fetch_paginated_call_deterministic('fetchOHLCV', $symbol, $since, $limit, $timeframe, $params, $maxHistoricalLimit);
        }
        $until = $this->safe_integer($params, 'until');
        $historical = false;
        list($historical, $params) = $this->handle_option_and_params($params, 'fetchOHLCV', 'historical');
        $timeframeOption = $this->safe_dict($this->options, 'timeframes', array());
        $contractTimeframes = $this->safe_dict($timeframeOption, 'contract', array());
        $market = $this->market($symbol);
        $request = array(
            'symbol' => $market['id'],
            'interval' => $this->safe_string($contractTimeframes, $timeframe, $timeframe),
        );
        $priceType = $this->safe_string_upper($params, 'price');
        $params = $this->omit($params, array( 'historical', 'until', 'price' ));
        $response = null;
        if ($historical) {
            if ($priceType !== null) {
                $request['priceType'] = $priceType;
            }
            $startTime = $since;
            $endTime = $until;
            if (($since === null) || ($until === null)) {
                $now = $this->milliseconds();
                $duration = $this->parse_timeframe($timeframe) * 1000;
                $numberOfCandles = $limit ? $limit : $maxHistoricalLimit;
                $timeDelta = $numberOfCandles * $duration;
                if (($since === null) && ($until === null)) {
                    $endTime = $now;
                    $startTime = $now - $timeDelta;
                } elseif ($since === null) {
                    $startTime = $until - $timeDelta;
                } else {
                    $endTime = $since . $timeDelta;
                }
            }
            $request['startTime'] = $startTime;
            $request['endTime'] = $endTime;
            $response = $this->contractGetCapiV3MarketHistoryKlines ($this->extend($request, $params));
        } else {
            if ($limit !== null) {
                $request['limit'] = $limit;
            }
            if ($priceType === 'MARK') {
                $response = $this->contractGetCapiV3MarketMarkPriceKlines ($this->extend($request, $params));
            } elseif ($priceType === 'INDEX') {
                $response = $this->contractGetCapiV3MarketIndexPriceKlines ($this->extend($request, $params));
            } else {
                $response = $this->contractGetCapiV3MarketKlines ($this->extend($request, $params));
            }
        }
        return $this->parse_ohlcvs($response, $market, $timeframe, $since, $limit);
    }

    public function parse_ohlcv($ohlcv, ?array $market = null): array {
        return array(
            $this->safe_integer($ohlcv, 0),
            $this->safe_number($ohlcv, 1),
            $this->safe_number($ohlcv, 2),
            $this->safe_number($ohlcv, 3),
            $this->safe_number($ohlcv, 4),
            $this->safe_number($ohlcv, 5),
        );
    }

