    public function parse_trade(array $trade, ?array $market = null): array {
        //
        // fetchTrades
        //     {
        //         "id" => "875fba11-f8a1-42ad-915d-012ccb375e8a",
        //         "price" => "2114.77",
        //         "qty" => "0.01000",
        //         "quoteQty" => "21.1477000",
        //         "time" => 1775594995485,
        //         "isBuyerMaker" => false,
        //         "isBestMatch" => true
        //     }
        //
        // fetchMyTrades (spot)
        //     {
        //         "symbol" => "DOGEUSDT",
        //         "id" => 736825748291060702,
        //         "orderId" => 736825748215563230,
        //         "price" => "0.09349",
        //         "qty" => "250.0",
        //         "quoteQty" => "23.3725",
        //         "commission" => "0.0233725",
        //         "time" => 1775672947953,
        //         "isBuyer" => false
        //     }
        //
        // fetchMyTrades (contract)
        //     {
        //         "id" => 737074389731770728,
        //         "orderId" => 737074043320009064,
        //         "symbol" => "DOGEUSDT",
        //         "buyer" => true,
        //         "commission" => "0.00183500",
        //         "commissionAsset" => "USDT",
        //         "maker" => true,
        //         "price" => "0.09175",
        //         "qty" => "100",
        //         "quoteQty" => "9.17500",
        //         "realizedPnl" => "0",
        //         "side" => "BUY",
        //         "positionSide" => "LONG",
        //         "time" => 1775732228692
        //     }
        //
        $timestamp = $this->safe_integer($trade, 'time');
        $isBuyer = $this->safe_bool($trade, 'isBuyer');
        $side = $this->safe_string_lower($trade, 'side');
        if ($isBuyer !== null) {
            $side = $isBuyer ? 'buy' : 'sell';
        }
        $isSpot = true;
        if ($market === null) {
            $marketId = $this->safe_string($trade, 'symbol');
            $realizedPnl = $this->safe_string($trade, 'realizedPnl');
            $marketType = ($realizedPnl !== null) ? 'swap' : 'spot';
            $market = $this->safe_market($marketId, null, null, $marketType);
            $isSpot = $marketType === 'spot';
        } else {
            $isSpot = $market['spot'];
        }
        $fee = null;
        $commission = $this->safe_string($trade, 'commission');
        if ($commission !== null) {
            $commissionAsset = $this->safe_string($trade, 'commissionAsset');
            $feeCurrency = $this->safe_currency_code($commissionAsset);
            if ($isSpot) {
                if ($side === 'buy') {
                    $feeCurrency = $market['base'];
                } else {
                    $feeCurrency = $market['quote'];
                }
            }
            $fee = array(
                'cost' => $commission,
                'currency' => $feeCurrency,
            );
        }
        $isMaker = $this->safe_bool($trade, 'maker');
        $takerOrMaker = null;
        if ($isMaker !== null) {
            $takerOrMaker = $isMaker ? 'maker' : 'taker';
        }
        return $this->safe_trade(array(
            'info' => $trade,
            'id' => $this->safe_string($trade, 'id'),
            'order' => $this->safe_string($trade, 'orderId'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $market['symbol'],
            'type' => null,
            'takerOrMaker' => $takerOrMaker,
            'side' => $side,
            'price' => $this->safe_string($trade, 'price'),
            'amount' => $this->safe_string($trade, 'qty'),
            'cost' => $this->safe_string($trade, 'quoteQty'),
            'fee' => $fee,
        ), $market);
    }

