            //         "updateTime" => 1775666888536,
            //         "isWorking" => true
            //     }
            //
            $response = $this->privateGetApiV3Order ($this->extend($request, $params));
        } else {
            $response = $this->contractPrivateGetCapiV3Order ($this->extend($request, $params));
        }
        return $this->parse_order($response, $market);
