        //         "type" => "TAKE_PROFIT_MARKET",
        //         "updateTime" => 1775732228695,
        //         "workingType" => "CONTRACT_PRICE"
        //     }
        //
        $errorCode = $this->safe_string($order, 'errorCode');
        $errorMessage = $this->safe_string($order, 'errorMsg');
        if (($errorCode !== null) || ($errorMessage !== null)) {
            $this->handle_order_or_position_error($errorCode, $errorMessage, $order);
        }
        if ($market === null) {
            $marketId = $this->safe_string($order, 'symbol');
            $positionSide = $this->safe_string($order, 'positionSide');
            $marketType = ($positionSide === null) ? 'spot' : 'swap';
            $market = $this->safe_market($marketId, null, null, $marketType);
        }
        $timestamp = $this->safe_integer_n($order, array( 'transactTime', 'time', 'createTime' ));
        $rawStatus = $this->safe_string_lower($order, 'status');
        $triggerPrice = $this->omit_zero($this->safe_string_2($order, 'triggerPrice', 'stopPrice'));
        $rawType = $this->safe_string_upper_2($order, 'type', 'orderType');
        $takeProfitPrice = null;
        $stopLossPrice = null;
        if ($rawType === 'TAKE_PROFIT_MARKET' || $rawType === 'TAKE_PROFIT') {
            $takeProfitPrice = $triggerPrice;
        } elseif ($rawType === 'STOP_LOSS' || $rawType === 'STOP' || $rawType === 'STOP_MARKET') {
            $stopLossPrice = $triggerPrice;
        }
        return $this->safe_order(array(
            'id' => $this->safe_string_n($order, array( 'orderId', 'algoId', 'successOrderId' )),
            'clientOrderId' => $this->safe_string_n($order, array( 'clientOrderId', 'origClientOrderId', 'clientAlgoId' )),
            'symbol' => $this->safe_string($market, 'symbol'),
            'type' => $this->parse_order_type($rawType),
            'timeInForce' => $this->safe_string($order, 'timeInForce'),
            'postOnly' => null,
            'reduceOnly' => $this->safe_bool($order, 'reduceOnly'),
            'side' => $this->safe_string_lower($order, 'side'),
            'amount' => $this->safe_string_2($order, 'origQty', 'quantity'),
            'price' => $this->safe_string($order, 'price'),
            'triggerPrice' => $triggerPrice,
            'cost' => $this->safe_string_2($order, 'cummulativeQuoteQty', 'cumQuote'),
            'filled' => $this->safe_string($order, 'executedQty'),
            'remaining' => null,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'fee' => null,
            'status' => $this->parse_order_status($rawStatus),
            'lastTradeTimestamp' => null,
            'lastUpdateTimestamp' => $this->safe_integer($order, 'updateTime'),
            'average' => $this->safe_string($order, 'avgPrice'),
            'trades' => null,
            'stopLossPrice' => $stopLossPrice,
            'takeProfitPrice' => $takeProfitPrice,
            'info' => $order,
        ), $market);
    }

    public function parse_order_status(?string $status) {
        $statuses = array(
            'new' => 'open',
            'partial_fill' => 'closed',
            'full_fill' => 'closed',
            'filled' => 'closed',
            'cancelled' => 'canceled',
            'canceled' => 'canceled',
            'rejected' => 'rejected',
            'untriggered' => 'open',
        );
        return $this->safe_string($statuses, $status, $status);
    }

    public function parse_order_type(?string $type) {
        $types = array(
            'LIMIT' => 'limit',
            'MARKET' => 'market',
            'STOP_LOSS' => 'limit',
            'STOP' => 'limit',
            'TAKE_PROFIT' => 'limit',
            'TAKE_PROFIT_MARKET' => 'market',
            'STOP_MARKET' => 'market',
        );
        return $this->safe_string($types, $type, $type);
    }

    public function handle_order_or_position_error(?string $errorCode, ?string $errorMessage, array $order) {
        if ($errorCode === null) {
            $errorCode = '';
        }
        if ($errorMessage === null) {
            $errorMessage = '';
        }
        if (($errorCode === '') && ($errorMessage === '')) {
            // some endpoints could return an empty string if there is no error
            return;
        }
        $feedback = $this->id . ' ' . $this->json($order);
        $this->throw_exactly_matched_exception($this->exceptions['exact'], $errorMessage, $feedback);
        $this->throw_exactly_matched_exception($this->exceptions['exact'], $errorCode, $feedback);
        $this->throw_broadly_matched_exception($this->exceptions['broad'], $errorMessage, $feedback);
        $this->throw_broadly_matched_exception($this->exceptions['broad'], $errorCode, $feedback);
        throw new InvalidOrder($feedback);
    }

    public function fetch_order_trades(string $id, ?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()) {
        /**
         * fetch all the trades made from a single order
         *
         * @see https://www.weex.com/api-doc/spot/orderApi/TransactionDetails // spot
         * @see https://www.weex.com/api-doc/contract/Transaction_API/GetTradeDetails // contract
         *
         * @param {string} $id order $id
         * @param {string} [$symbol] unified market $symbol
         * @param {int} [$since] the earliest time in ms to fetch trades for
         * @param {int} [$limit] the maximum number of trades to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array[]} a list of ~@link https://docs.ccxt.com/?$id=trade-structure trade structures~
         */
        $this->load_markets();
        $request = array(
            'orderId' => $id,
        );
        return $this->fetch_my_trades($symbol, $since, $limit, $this->extend($request, $params));
    }

    public function fetch_my_trades(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         *
         * @see https://www.weex.com/api-doc/spot/orderApi/TransactionDetails // spot
         * @see https://www.weex.com/api-doc/contract/Transaction_API/GetTradeDetails // contract
         *
         * fetch all trades made by the user
         * @param {string} $symbol unified $market $symbol
         * @param {int} [$since] the earliest time in ms to fetch trades for
         * @param {int} [$limit] the maximum number of trades structures to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-$params)
         * @param {string} [$params->type] 'spot' or 'swap', used if $symbol is not provided (default is 'spot')
         * @return {Trade[]} a list of ~@link https://docs.ccxt.com/?id=trade-structure trade structures~
         */
        $this->load_markets();
        $market = null;
        if ($symbol !== null) {
            $market = $this->market($symbol);
        }
        $marketType = null;
        list($marketType, $params) = $this->handle_market_type_and_params('fetchMyTrades', $market, $params);
        $isSpot = ($marketType === 'spot');
        if ($isSpot && ($symbol === null)) {
            throw new ArgumentsRequired($this->id . ' fetchMyTrades() requires a $symbol argument for spot markets');
        }
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchMyTrades', 'paginate', false);
        $maxLimit = 100;
        if ($paginate) {
            return $this->fetch_paginated_call_dynamic('fetchMyTrades', $symbol, $since, $limit, $params, $maxLimit);
        }
        $request = array();
        if ($symbol !== null) {
            $request['symbol'] = $market['id'];
        }
        if ($since !== null) {
            $request['startTime'] = $since;
        }
        if ($limit !== null) {
            $request['limit'] = $limit;
        }
        list($request, $params) = $this->handle_until_option('endTime', $request, $params);
        $response = null;
        if ($isSpot) {
            //
            //     array(
            //         {
            //             "symbol" => "DOGEUSDT",
            //             "id" => 736825748291060702,
            //             "orderId" => 736825748215563230,
            //             "price" => "0.09349",
            //             "qty" => "250.0",
            //             "quoteQty" => "23.3725",
            //             "commission" => "0.0233725",
            //             "time" => 1775672947953,
            //             "isBuyer" => false
            //         }
            //     )
            //
            $response = $this->privateGetApiV3MyTrades ($this->extend($request, $params));
        } else {
            //
            //     array(
            //         {
            //             "id" => 737074389731770728,
            //             "orderId" => 737074043320009064,
            //             "symbol" => "DOGEUSDT",
            //             "buyer" => true,
            //             "commission" => "0.00183500",
            //             "commissionAsset" => "USDT",
            //             "maker" => true,
            //             "price" => "0.09175",
            //             "qty" => "100",
            //             "quoteQty" => "9.17500",
            //             "realizedPnl" => "0",
            //             "side" => "BUY",
            //             "positionSide" => "LONG",
            //             "time" => 1775732228692
            //         }
            //     )
            //
            $response = $this->contractPrivateGetCapiV3UserTrades ($this->extend($request, $params));
        }
        return $this->parse_trades($response, $market, $since, $limit);
    }

    public function fetch_ledger(?string $code = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetch the history of changes, actions done by the user or operations that altered the balance of the user
         *
         * @see https://www.weex.com/api-doc/spot/AccountAPI/GetBillRecords // spot
         * @see https://www.weex.com/api-doc/spot/AccountAPI/GetFundBillRecords // funding
         * @see https://www.weex.com/api-doc/contract/Account_API/GetContractBills // contract
         *
         * @param {string} [$code] unified $currency $code, default is null
         * @param {int} [$since] timestamp in ms of the earliest ledger entry, default is null
         * @param {int} [$limit] max number of ledger entries to return, default is null, max is 100
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {int} [$params->until] timestamp in ms of the latest ledger entry
         * @param {string} [$params->type] 'spot', 'funding' or 'swap' (default is 'spot')
         * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-$params)
         * @return {array} a ~@link https://docs.ccxt.com/?id=ledger-entry-structure ledger structure~
         */
        $this->load_markets();
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchLedger', 'paginate', false);
        $maxLimit = 100;
        if ($paginate) {
            return $this->fetch_paginated_call_dynamic('fetchLedger', $code, $since, $limit, $params, $maxLimit);
        }
        $accountType = null;
        list($accountType, $params) = $this->handle_market_type_and_params('fetchLedger', null, $params);
        $accountsByType = $this->safe_dict($this->options, 'accountsByType', array());
        $accountType = $this->safe_string($accountsByType, $accountType, $accountType);
        $request = array();
        $items = null;
        $currency = null;
        if ($code !== null) {
            $currency = $this->currency($code);
        }
        if ($accountType === 'contract') {
            if ($code !== null) {
                $request['currency'] = $currency['id'];
            }
            if ($since !== null) {
                $request['startTime'] = $since;
            }
            if ($limit !== null) {
                $request['limit'] = $limit;
            }
            list($request, $params) = $this->handle_until_option('endTime', $request, $params);
            $contractResponse = $this->contractPrivatePostCapiV3AccountIncome ($this->extend($request, $params));
            $items = $this->safe_list($contractResponse, 'items', array());
        } elseif ($accountType === 'funding') {
            if ($since !== null) {
                $request['startTime'] = $since;
            }
            if ($limit !== null) {
                $request['pageSize'] = $limit;
            }
            list($request, $params) = $this->handle_until_option('endTime', $request, $params);
            $fundingResponse = $this->privatePostApiV3AccountFundingBills ($this->extend($request, $params));
            $items = $this->safe_list($fundingResponse, 'items', array());
        } else {
            if ($since !== null) {
                $request['after'] = $since;
            }
            if ($limit !== null) {
                $request['limit'] = $limit;
            }
            list($request, $params) = $this->handle_until_option('before', $request, $params);
            $items = $this->privatePostApiV3AccountBills ($this->extend($request, $params));
        }
        return $this->parse_ledger($items, $currency, $since, $limit);
    }

    public function parse_ledger_entry(array $item, ?array $currency = null): array {
        //
        // spot
        //     {
        //         "billId" => "736825748291061726",
        //         "coinId" => 82,
        //         "coinName" => "DOGE",
        //         "bizType" => "trade_out",
        //         "fillSize" => "250.0",
        //         "fillValue" => "23.372500",
        //         "deltaAmount" => "-250.0",
        //         "afterAmount" => "49.70000000",
        //         "fees" => "0",
        //         "cTime" => "1775672947953"
        //     }
        //
        // contract
        //     {
        //         "billId" => 736791763716407518,
        //         "asset" => "USDT",
        //         "symbol" => null,
        //         "income" => "-90.00000000",
        //         "incomeType" => "withdraw",
        //         "balance" => "106.00000000",
        //         "fillFee" => "0",
        //         "time" => 1775664845399,
        //         "transferReason" => "UNKNOWN_TRANSFER_REASON"
        //     }
        //
        // funding
        //     {
        //         "billId" => "16502414",
        //         "coinId" => 2,
        //         "coinName" => "USDT",
        //         "bizType" => "transfer_out",
        //         "fillSize" => null,
        //         "fillValue" => null,
        //         "deltaAmount" => "-100.00000000",
        //         "afterAmount" => "0.00000000",
        //         "fees" => "0.00000000",
        //         "cTime" => "1775664588931"
        //     }
        //
        $currencyId = $this->safe_string_2($item, 'coinName', 'asset');
        $code = $this->safe_currency_code($currencyId, $currency);
        $currency = $this->safe_currency($currencyId, $currency);
        $timestamp = $this->safe_integer_2($item, 'cTime', 'time');
        $amountRaw = $this->safe_string_2($item, 'deltaAmount', 'income');
        $after = $this->safe_string_2($item, 'afterAmount', 'balance');
        $before = Precise::string_sub($after, $amountRaw);
        $amount = $this->parse_number(Precise::string_abs($amountRaw));
        $direction = 'in';
        if (mb_strpos($amountRaw, '-') !== false) {
            $direction = 'out';
        }
        $rawType = $this->safe_string_2($item, 'bizType', 'incomeType');
        $transferReason = $this->safe_string($item, 'transferReason');
        $isContractEntry = ($transferReason !== null);
        if ($isContractEntry) {
            if (($rawType === 'withdraw') || ($rawType === 'deposit')) {
                $rawType = 'transfer';
            }
        }
        return $this->safe_ledger_entry(array(
            'info' => $item,
            'id' => $this->safe_string($item, 'billId'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'direction' => $direction,
            'account' => null,
            'referenceId' => null,
            'referenceAccount' => null,
            'type' => $this->parse_ledger_type($rawType),
            'currency' => $code,
            'amount' => $amount,
            'before' => $this->parse_number($before),
            'after' => $this->parse_number($after),
            'status' => null,
            'fee' => array(
                'currency' => $code,
                'cost' => $this->safe_number_2($item, 'fees', 'fillFee'),
            ),
        ), $currency);
    }

    public function parse_ledger_type(?string $type) {
        $types = array(
            'transfer_in' => 'transfer',
            'transfer_out' => 'transfer',
            'deposit' => 'deposit',
            'withdraw' => 'withdrawal',
            'trade_in' => 'trade',
            'trade_out' => 'trade',
            'position_open_long' => 'trade',
            'position_open_short' => 'trade',
            'position_close_long' => 'trade',
            'position_close_short' => 'trade',
        );
        return $this->safe_string($types, $type, $type);
    }

